import re, unicodedata
from typing import Optional

def normalize(text: str) -> str:
    """NFKC-normalize and collapse whitespace to defeat Unicode substitutions."""
    text = unicodedata.normalize("NFKC", text)
    text = re.sub(r"[\s\-_\.]{1,3}", " ", text)  # collapse word-splitting tricks
    return text.lower()

# Patterns operate on normalized text
DENY_PATTERNS: list[tuple[str, re.Pattern]] = [
    ("weapon_synthesis", re.compile(
        r"(synthesize|manufacture|make|produce).{0,30}(nerve agent|sarin|vx |ricin|anthrax|explosiv)"
    )),
    ("malware_creation", re.compile(
        r"(write|create|build|code).{0,25}(ransomware|keylogger|rootkit|rat |trojan|wiper)"
    )),
    ("csam", re.compile(
        r"(child|minor|underage|prepubescent).{0,20}(nude|naked|sexual|explicit|porn)"
    )),
    ("credential_stuffing", re.compile(
        r"(automate|script|bulk).{0,30}(login|sign.?in|account).{0,20}(list|combo|breach)"
    )),
]

def keyword_check(raw_input: str) -> Optional[tuple[str, str]]:
    """Returns (category, matched_pattern) or None if clean."""
    normed = normalize(raw_input)
    for category, pattern in DENY_PATTERNS:
        m = pattern.search(normed)
        if m:
            return category, m.group(0)
    return None

import logging
from dataclasses import dataclass

logger = logging.getLogger("guardrails")

@dataclass
class InputFilterResult:
    allowed: bool
    block_reason: str = ""
    category: str = "safe"
    scrubbed_input: str = ""

def run_input_filters(raw_input: str, user_id: str) -> InputFilterResult:
    # 1. Keyword / regex check (< 1 ms)
    kw = keyword_check(raw_input)
    if kw:
        category, snippet = kw
        logger.warning("input_blocked_keyword",
                       extra={"user": hash_user_id(user_id), "category": category})
        return InputFilterResult(allowed=False, block_reason=f"keyword:{category}",
                                 category=category)

    # 2. Scrub PII before any further processing or logging
    scrubbed = scrub_pii_for_log(raw_input)

    # 3. LLM safety classifier (~100–150 ms)
    clf = llm_classify(raw_input)
    if clf.category in ("harmful", "jailbreak") and clf.confidence >= 0.80:
        logger.warning("input_blocked_classifier", extra={
            "user": hash_user_id(user_id), "category": clf.category,
            "confidence": clf.confidence, "reason": clf.reason,
        })
        return InputFilterResult(allowed=False, block_reason=f"classifier:{clf.category}",
                                 category=clf.category)

    return InputFilterResult(allowed=True, category=clf.category,
                             scrubbed_input=scrubbed)

OUTPUT_HARM_PATTERNS: list[tuple[str, re.Pattern]] = [
    ("weapon_instructions", re.compile(
        r"(step \d|first[,:]|then[,:]|next[,:]|finally[,:]).{0,100}"
        r"(mix|combine|dissolve|heat).{0,80}(acid|chlorine|ammonia|hydrogen peroxide)", re.I
    )),
    ("malware_payload", re.compile(
        r"(os\.system|subprocess\.run|exec\(|eval\().{0,300}"
        r"(rm -rf|del /f /s|format c:|shutdown -r)", re.I
    )),
    ("csam_output", re.compile(
        r"(child|minor|underage).{0,30}(nude|naked|sexual|explicit)", re.I
    )),
]

def harm_scan_output(output: str) -> Optional[tuple[str, str]]:
    """Returns (category, snippet) if harmful content found, else None."""
    for category, pattern in OUTPUT_HARM_PATTERNS:
        m = pattern.search(output)
        if m:
            return category, m.group(0)[:80]
    return None

# Requires: pip install anthropic sentence-transformers numpy
import numpy as np

try:
    from sentence_transformers import SentenceTransformer
    _embed_model = SentenceTransformer("all-MiniLM-L6-v2")
    EMBEDDING_AVAILABLE = True
except ImportError:
    EMBEDDING_AVAILABLE = False

# Define allowed topic centroids (pre-computed at startup)
ALLOWED_TOPIC_SAMPLES = [
    "Python functions, classes, async/await",
    "REST API design, HTTP methods, JSON schemas",
    "Database queries, SQL, ORM models",
    "Git workflows, branching, pull requests",
    "Docker containers, Kubernetes pods, CI/CD pipelines",
]

def _embed(texts: list[str]) -> np.ndarray:
    return _embed_model.encode(texts, normalize_embeddings=True)

if EMBEDDING_AVAILABLE:
    _topic_centroid = _embed(ALLOWED_TOPIC_SAMPLES).mean(axis=0)
    _topic_centroid /= np.linalg.norm(_topic_centroid)

def topic_drift_score(output: str) -> float:
    """Cosine similarity to allowed topic centroid. 1.0 = on-topic, 0.0 = off-topic."""
    if not EMBEDDING_AVAILABLE:
        return 1.0   # skip check if library not installed
    vec = _embed([output])[0]
    return float(np.dot(vec, _topic_centroid))

TOPIC_DRIFT_THRESHOLD = 0.30  # tune per application

@dataclass
class OutputFilterResult:
    safe: bool
    block_reason: str = ""
    redacted_output: str = ""

def run_output_filters(raw_output: str, user_id: str) -> OutputFilterResult:
    # 1. Harm patterns
    harm = harm_scan_output(raw_output)
    if harm:
        category, snippet = harm
        logger.warning("output_blocked_harm", extra={
            "user": hash_user_id(user_id), "category": category, "snippet": snippet,
        })
        return OutputFilterResult(safe=False, block_reason=f"harm:{category}")

    # 2. PII leakage
    pii_hits = pii_scan_output(raw_output)
    if pii_hits:
        # Redact rather than block entirely — preserve usefulness
        cleaned = raw_output
        for label, value in pii_hits:
            cleaned = cleaned.replace(value, f"[{label}]")
        logger.warning("output_pii_redacted", extra={
            "user": hash_user_id(user_id), "types": [h[0] for h in pii_hits],
        })
        return OutputFilterResult(safe=True, redacted_output=cleaned)

    # 3. Topic drift (only if embedding model available)
    drift = topic_drift_score(raw_output)
    if drift < TOPIC_DRIFT_THRESHOLD:
        logger.warning("output_topic_drift", extra={
            "user": hash_user_id(user_id), "score": drift,
        })
        return OutputFilterResult(safe=False, block_reason=f"topic_drift:{drift:.2f}")

    return OutputFilterResult(safe=True, redacted_output=raw_output)

import hashlib, functools

@functools.lru_cache(maxsize=4096)
def _cached_classify(input_hash: str, input_text: str) -> str:
    """Cache key is a (hash, truncated-text) pair to avoid hash collisions."""
    return llm_classify(input_text).category

def classify_with_cache(raw_input: str) -> str:
    normed = normalize(raw_input)[:500]   # cap length for cache key
    h = hashlib.sha256(normed.encode()).hexdigest()[:16]
    return _cached_classify(h, normed)
